//! bench-cat-map-action — MolmoAct2 action-expert cat-map fast-path benchmark.
//!
//! This isolates the runtime question to the flow-matching action expert:
//! image/VLM/depth context is prepared once, then canonical and cat-map routed
//! action flows run over the same KV cache.
//!
//! Usage:
//!   bench-cat-map-action --knot /path/molmoact2.knot \
//!     [--pixels CHW.f32] [--text-tokens 13780,705,279,1633] \
//!     [--horizon 30] [--seed 42] [--route mod5] \
//!     [--eps 1e-3,1e-4,1e-5] [--warmup 1] [--repeats 3]

use std::path::PathBuf;
use std::process::exit;
use std::time::Instant;

use distributed_inference::cat_map_route::CertifiedCatRoute;
use distributed_inference::model_molmoact2::MolmoAct2Pipeline;

fn die(msg: impl AsRef<str>) -> ! {
    eprintln!("bench-cat-map-action: {}", msg.as_ref());
    exit(2);
}

#[derive(Clone, Debug)]
struct Cli {
    knot: PathBuf,
    pixels_path: Option<PathBuf>,
    text_tokens: Vec<u32>,
    horizon: usize,
    seed: u64,
    route: CertifiedCatRoute,
    epsilons: Vec<f32>,
    warmup: usize,
    repeats: usize,
}

#[derive(Clone, Debug)]
struct ActionStats {
    finite: bool,
    std: f32,
    max_abs: f32,
}

#[derive(Clone, Debug)]
struct DriftStats {
    finite: bool,
    rms: f32,
    max_abs: f32,
}

fn main() {
    let cli = parse_cli();

    eprintln!("[bench-cat-map-action] loading {}", cli.knot.display());
    let load_started = Instant::now();
    let mut pipe = MolmoAct2Pipeline::load(
        cli.knot
            .to_str()
            .unwrap_or_else(|| die("non-utf8 knot path")),
    );
    eprintln!(
        "[bench-cat-map-action] loaded in {}ms",
        load_started.elapsed().as_millis()
    );

    let pixels = load_or_synthesize_pixels(&pipe, cli.pixels_path.as_ref());
    let mut text_tokens = cli.text_tokens.clone();
    if text_tokens.is_empty() {
        text_tokens = vec![13780, 705, 279, 1633];
    }

    eprintln!(
        "[bench-cat-map-action] preparing action context: pixels={} tokens={} horizon={} seed={}",
        pixels.len(),
        text_tokens.len(),
        cli.horizon,
        cli.seed
    );
    let context_started = Instant::now();
    let context = pipe
        .prepare_action_context(&pixels, &text_tokens)
        .unwrap_or_else(|error| die(format!("prepare_action_context failed: {error}")));
    let context_ms = context_started.elapsed().as_millis();
    eprintln!(
        "[bench-cat-map-action] context ready in {context_ms}ms total_seq={}",
        context.total_seq
    );

    for _ in 0..cli.warmup {
        let _ = pipe
            .action_expert
            .generate(&context.kv, context.total_seq, cli.horizon, cli.seed)
            .unwrap_or_else(|error| die(format!("canonical warmup failed: {error}")));
        for &epsilon in &cli.epsilons {
            let _ = pipe
                .action_expert
                .generate_with_cat_map_fast_path(
                    &context.kv,
                    context.total_seq,
                    cli.horizon,
                    cli.seed,
                    cli.route,
                    epsilon,
                )
                .unwrap_or_else(|error| die(format!("cat-map warmup failed: {error}")));
        }
    }

    println!(
        "mode,route,epsilon,repeat,ms,executed_steps,skipped_steps,converged,rms_drift,max_drift,action_std,action_max_abs"
    );

    for repeat in 0..cli.repeats {
        let canonical_started = Instant::now();
        let canonical = pipe
            .action_expert
            .generate(&context.kv, context.total_seq, cli.horizon, cli.seed)
            .unwrap_or_else(|error| die(format!("canonical run failed: {error}")));
        let canonical_ms = canonical_started.elapsed().as_millis();
        let canonical_stats = action_stats(&canonical);
        println!(
            "canonical,,,{repeat},{canonical_ms},,,,0.000000,0.000000,{:.6},{:.6}",
            canonical_stats.std, canonical_stats.max_abs
        );
        if !canonical_stats.finite {
            die("canonical action contains non-finite values");
        }

        for &epsilon in &cli.epsilons {
            let fast_started = Instant::now();
            let fast = pipe
                .action_expert
                .generate_with_cat_map_fast_path(
                    &context.kv,
                    context.total_seq,
                    cli.horizon,
                    cli.seed,
                    cli.route,
                    epsilon,
                )
                .unwrap_or_else(|error| die(format!("cat-map run failed: {error}")));
            let fast_ms = fast_started.elapsed().as_millis();
            let fast_stats = action_stats(&fast.action);
            let drift = drift_stats(&canonical, &fast.action);
            if !fast_stats.finite || !drift.finite {
                die("cat-map fast-path action or drift contains non-finite values");
            }
            println!(
                "cat_map_fast_path,{},{epsilon:.8e},{repeat},{fast_ms},{},{},{},{:.6},{:.6},{:.6},{:.6}",
                route_label(cli.route),
                fast.cat_map_fast_path.executed_steps(),
                fast.cat_map_fast_path.skipped_steps(),
                fast.cat_map_fast_path.converged(),
                drift.rms,
                drift.max_abs,
                fast_stats.std,
                fast_stats.max_abs
            );
        }
    }
}

fn parse_cli() -> Cli {
    let raw: Vec<String> = std::env::args().collect();
    let mut knot: Option<PathBuf> = None;
    let mut pixels_path: Option<PathBuf> = None;
    let mut text_tokens: Vec<u32> = Vec::new();
    let mut horizon = 30usize;
    let mut seed = 42u64;
    let mut route = CertifiedCatRoute::Mod5;
    let mut epsilons = vec![1.0e-3, 1.0e-4, 1.0e-5];
    let mut warmup = 1usize;
    let mut repeats = 3usize;

    let mut i = 1;
    while i < raw.len() {
        match raw[i].as_str() {
            "--knot" => {
                i += 1;
                knot = Some(PathBuf::from(
                    raw.get(i).unwrap_or_else(|| die("--knot needs a path")),
                ));
            }
            "--pixels" => {
                i += 1;
                pixels_path = Some(PathBuf::from(
                    raw.get(i).unwrap_or_else(|| die("--pixels needs a path")),
                ));
            }
            "--text-tokens" => {
                i += 1;
                text_tokens = parse_u32_csv(
                    raw.get(i)
                        .unwrap_or_else(|| die("--text-tokens needs a CSV")),
                );
            }
            "--horizon" => {
                i += 1;
                horizon = raw
                    .get(i)
                    .unwrap_or_else(|| die("--horizon needs a value"))
                    .parse()
                    .unwrap_or_else(|error| die(format!("--horizon: {error}")));
            }
            "--seed" => {
                i += 1;
                seed = raw
                    .get(i)
                    .unwrap_or_else(|| die("--seed needs a value"))
                    .parse()
                    .unwrap_or_else(|error| die(format!("--seed: {error}")));
            }
            "--route" => {
                i += 1;
                route = parse_route(
                    raw.get(i)
                        .unwrap_or_else(|| die("--route needs mod2/mod3/mod5")),
                );
            }
            "--eps" => {
                i += 1;
                epsilons = parse_f32_csv(raw.get(i).unwrap_or_else(|| die("--eps needs a CSV")));
            }
            "--warmup" => {
                i += 1;
                warmup = raw
                    .get(i)
                    .unwrap_or_else(|| die("--warmup needs a value"))
                    .parse()
                    .unwrap_or_else(|error| die(format!("--warmup: {error}")));
            }
            "--repeats" => {
                i += 1;
                repeats = raw
                    .get(i)
                    .unwrap_or_else(|| die("--repeats needs a value"))
                    .parse()
                    .unwrap_or_else(|error| die(format!("--repeats: {error}")));
            }
            "-h" | "--help" => {
                eprintln!("usage: bench-cat-map-action --knot <path> [--pixels <chw.f32>] [--text-tokens <csv>] [--horizon N] [--seed N] [--route mod5] [--eps <csv>] [--warmup N] [--repeats N]");
                exit(0);
            }
            other => die(format!("unknown arg {other:?}")),
        }
        i += 1;
    }

    if epsilons.is_empty() {
        die("--eps must contain at least one epsilon");
    }
    if repeats == 0 {
        die("--repeats must be greater than zero");
    }

    Cli {
        knot: knot.unwrap_or_else(|| die("--knot required")),
        pixels_path,
        text_tokens,
        horizon,
        seed,
        route,
        epsilons,
        warmup,
        repeats,
    }
}

fn load_or_synthesize_pixels(pipe: &MolmoAct2Pipeline, pixels_path: Option<&PathBuf>) -> Vec<f32> {
    let img_size = pipe.config.vit_config.image_size;
    let n_px = 3 * img_size * img_size;
    match pixels_path {
        Some(path) => {
            let bytes = std::fs::read(path)
                .unwrap_or_else(|error| die(format!("read {}: {error}", path.display())));
            if bytes.len() != n_px * 4 {
                die(format!(
                    "pixels: have {} bytes, need {} ({}x{}x3 f32)",
                    bytes.len(),
                    n_px * 4,
                    img_size,
                    img_size
                ));
            }
            bytes
                .chunks_exact(4)
                .map(|chunk| f32::from_le_bytes([chunk[0], chunk[1], chunk[2], chunk[3]]))
                .collect()
        }
        None => {
            let mut pixels = vec![0.0f32; n_px];
            for c in 0..3 {
                for y in 0..img_size {
                    for x in 0..img_size {
                        let g = ((x + y) as f32 / (2.0 * img_size as f32) + c as f32 * 0.13) % 1.0;
                        pixels[c * img_size * img_size + y * img_size + x] = (g - 0.5) / 0.5;
                    }
                }
            }
            pixels
        }
    }
}

fn parse_u32_csv(raw: &str) -> Vec<u32> {
    raw.split(',')
        .filter(|part| !part.trim().is_empty())
        .map(|part| {
            part.trim()
                .parse()
                .unwrap_or_else(|error| die(format!("token {:?}: {error}", part.trim())))
        })
        .collect()
}

fn parse_f32_csv(raw: &str) -> Vec<f32> {
    raw.split(',')
        .filter(|part| !part.trim().is_empty())
        .map(|part| {
            let value: f32 = part
                .trim()
                .parse()
                .unwrap_or_else(|error| die(format!("epsilon {:?}: {error}", part.trim())));
            if !value.is_finite() || value < 0.0 {
                die(format!(
                    "epsilon {:?} must be finite and non-negative",
                    part.trim()
                ));
            }
            value
        })
        .collect()
}

fn parse_route(raw: &str) -> CertifiedCatRoute {
    match raw {
        "mod5" | "5" => CertifiedCatRoute::Mod5,
        "mod3" | "3" => CertifiedCatRoute::Mod3,
        "mod2" | "2" => CertifiedCatRoute::Mod2,
        _ => die("--route must be one of mod2, mod3, mod5"),
    }
}

fn route_label(route: CertifiedCatRoute) -> &'static str {
    match route {
        CertifiedCatRoute::Mod2 => "mod2",
        CertifiedCatRoute::Mod3 => "mod3",
        CertifiedCatRoute::Mod5 => "mod5",
    }
}

fn action_stats(action: &[f32]) -> ActionStats {
    if action.is_empty() {
        return ActionStats {
            finite: true,
            std: 0.0,
            max_abs: 0.0,
        };
    }
    let finite = action.iter().all(|value| value.is_finite());
    if !finite {
        return ActionStats {
            finite,
            std: f32::NAN,
            max_abs: f32::NAN,
        };
    }
    let mean = action.iter().sum::<f32>() / action.len() as f32;
    let variance = action
        .iter()
        .map(|value| {
            let delta = *value - mean;
            delta * delta
        })
        .sum::<f32>()
        / action.len() as f32;
    let max_abs = action
        .iter()
        .fold(0.0f32, |acc, &value| acc.max(value.abs()));
    ActionStats {
        finite,
        std: variance.sqrt(),
        max_abs,
    }
}

fn drift_stats(reference: &[f32], candidate: &[f32]) -> DriftStats {
    if reference.len() != candidate.len() || reference.is_empty() {
        return DriftStats {
            finite: false,
            rms: f32::NAN,
            max_abs: f32::NAN,
        };
    }
    let mut sum_sq = 0.0f64;
    let mut max_abs = 0.0f32;
    for i in 0..reference.len() {
        let delta = candidate[i] - reference[i];
        if !delta.is_finite() {
            return DriftStats {
                finite: false,
                rms: f32::NAN,
                max_abs: f32::NAN,
            };
        }
        sum_sq += (delta as f64) * (delta as f64);
        max_abs = max_abs.max(delta.abs());
    }
    DriftStats {
        finite: true,
        rms: (sum_sq / reference.len() as f64).sqrt() as f32,
        max_abs,
    }
}
